import React, { useState, useEffect } from 'react';
import { ShoppingCart, X, Trash2, Plus, Minus, ArrowRight } from 'lucide-react';
import { useApp } from '../store';
import { useNavigate } from 'react-router-dom';

const CartWidget = () => {
  const { cart, updateCartQuantity, removeFromCart } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [bump, setBump] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    if (cart.length === 0) return;
    setBump(true);
    const timer = setTimeout(() => setBump(false), 300);
    return () => clearTimeout(timer);
  }, [cart.length]);

  const subTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  return (
    <>
      {isOpen && (
        <div className="fixed inset-0 bg-black/80 z-[60] backdrop-blur-sm transition-opacity" onClick={() => setIsOpen(false)} />
      )}

      <div className={`fixed top-0 right-0 h-full w-full sm:w-[420px] bg-surface/95 border-l border-white/10 z-[70] transform transition-transform duration-300 ease-out shadow-2xl flex flex-col backdrop-blur-xl ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>

         {/* Header */}
         <div className="p-6 border-b border-white/5 flex justify-between items-center bg-black/20">
            <h2 className="text-xl font-bold text-white flex items-center gap-3">
                Səbətiniz
                <span className="bg-primary/20 text-primary text-xs px-2 py-1 rounded-full">{cart.length}</span>
            </h2>
            <button onClick={() => setIsOpen(false)} className="text-gray-400 hover:text-white p-2 hover:bg-white/5 rounded-full"><X /></button>
         </div>

         {/* Items */}
         <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {cart.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-4">
                    <div className="w-24 h-24 bg-surfaceHighlight rounded-full flex items-center justify-center mb-2">
                        <ShoppingCart className="w-10 h-10 opacity-30" />
                    </div>
                    <p className="font-medium text-lg">Səbətiniz boşdur</p>
                    <button onClick={() => setIsOpen(false)} className="text-primary hover:text-white transition-colors">Alış-verişə davam et</button>
                </div>
            ) : (
                cart.map((item, index) => (
                    <div key={index} className="flex gap-4 p-4 rounded-2xl bg-surfaceHighlight/50 border border-white/5 hover:border-primary/30 transition-colors group">
                        <div className="w-20 h-20 rounded-xl overflow-hidden bg-black/50 shrink-0">
                            <img src={item.image} className="w-full h-full object-cover group-hover:scale-105 transition-transform" alt={item.title} />
                        </div>
                        <div className="flex-1 flex flex-col justify-between">
                            <div>
                                <h4 className="font-bold text-white text-sm line-clamp-1">{item.title}</h4>
                                {item.userInput && <p className="text-xs text-gray-400 mt-1">{item.userInput}</p>}
                            </div>

                            <div className="flex items-center justify-between mt-3">
                                <div className="text-white font-bold">{item.price.toFixed(2)} <span className="text-primary text-xs">₼</span></div>

                                <div className="flex items-center gap-3">
                                    <div className="flex items-center bg-black/30 rounded-lg p-0.5">
                                        <button onClick={() => updateCartQuantity(index, -1)} className="p-1.5 text-gray-400 hover:text-white"><Minus className="w-3 h-3"/></button>
                                        <span className="text-xs font-bold w-6 text-center text-white">{item.quantity}</span>
                                        <button onClick={() => updateCartQuantity(index, 1)} className="p-1.5 text-gray-400 hover:text-white"><Plus className="w-3 h-3"/></button>
                                    </div>
                                    <button onClick={() => removeFromCart(index)} className="text-gray-500 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4"/></button>
                                </div>
                            </div>
                        </div>
                    </div>
                ))
            )}
         </div>

         {/* Footer */}
         <div className="p-6 border-t border-white/5 bg-black/20">
            <div className="flex justify-between mb-6">
                <span className="text-gray-400">Cəmi Məbləğ</span>
                <span className="text-2xl font-bold text-white">{subTotal.toFixed(2)} <span className="text-primary">₼</span></span>
            </div>
            <button 
                onClick={() => { setIsOpen(false); navigate('/cart'); }}
                className="w-full bg-white text-black font-bold py-4 rounded-xl hover:bg-gray-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                disabled={cart.length === 0}
            >
                Sifarişi Rəsmiləşdir <ArrowRight className="w-5 h-5" />
            </button>
         </div>
      </div>

      {/* Floating Button - Moved to Right to avoid Balance overlap */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 right-24 z-[50] glass text-white p-4 rounded-full shadow-lg transition-all duration-300 transform hover:scale-110 flex items-center justify-center group ${bump ? 'scale-110 ring-2 ring-primary' : ''}`}
      >
        <ShoppingCart className="w-6 h-6 text-primary group-hover:text-white transition-colors" />
        {cart.length > 0 && (
            <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full border-2 border-background shadow-sm">
                {cart.length}
            </span>
        )}
      </button>
    </>
  );
};

export default CartWidget;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useApp } from '../store';
import ProductCard from '../components/ProductCard';
import { ArrowLeft, Search, Filter, SlidersHorizontal, ArrowDownUp, Tag } from 'lucide-react';

const CategoryPage = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { categories, products } = useApp();
  const [search, setSearch] = useState('');
  const [sortOption, setSortOption] = useState<'default' | 'price-asc' | 'price-desc' | 'name-asc'>('default');
  const [selectedSubCat, setSelectedSubCat] = useState<string>('ALL');

  const category = categories.find(c => c.id === id);
  const categoryProducts = products.filter(p => p.categoryId === id);

  // Extract unique sub-categories
  const subCategories = Array.from(new Set(categoryProducts.map(p => p.subCategory).filter(Boolean))) as string[];

  // Filter & Sort Logic
  const filteredProducts = categoryProducts
    .filter(p => p.title.toLowerCase().includes(search.toLowerCase()))
    .filter(p => selectedSubCat === 'ALL' || p.subCategory === selectedSubCat)
    .sort((a, b) => {
        if (sortOption === 'price-asc') return a.price - b.price;
        if (sortOption === 'price-desc') return b.price - a.price;
        if (sortOption === 'name-asc') return a.title.localeCompare(b.title);
        return 0; // Default order
    });

  if (!category) {
      return (
        <div className="min-h-screen bg-gaming-dark flex items-center justify-center">
            <div className="text-center">
                <h2 className="text-2xl font-bold text-white mb-2">Kateqoriya Tapılmadı</h2>
                <button onClick={() => navigate('/')} className="text-gaming-neon hover:underline">Ana Səhifəyə Qayıt</button>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-gaming-dark pb-20 pt-28 px-4">
        <div className="max-w-7xl mx-auto">
            {/* Breadcrumb / Back */}
            <button onClick={() => navigate('/')} className="flex items-center text-gray-400 hover:text-white mb-6 group transition-colors">
                <div className="bg-slate-800 p-2 rounded-full mr-2 group-hover:bg-slate-700">
                    <ArrowLeft className="w-4 h-4" />
                </div>
                <span className="text-sm font-medium">Ana Səhifəyə Qayıt</span>
            </button>

            {/* Modern Header Banner */}
            <div className="relative rounded-3xl overflow-hidden mb-8 h-56 md:h-72 border border-gray-800 shadow-2xl group">
                {category.image ? (
                    <img src={category.image} className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-1000" alt={category.name} />
                ) : (
                    <div className="w-full h-full bg-slate-800" />
                )}
                <div className="absolute inset-0 bg-gradient-to-t from-gaming-dark via-gaming-dark/60 to-transparent flex flex-col justify-end p-8 md:p-12">
                     <h1 className="text-4xl md:text-6xl font-black text-white uppercase tracking-tighter mb-2 drop-shadow-lg">{category.name}</h1>
                     <p className="text-gray-300 text-lg flex items-center gap-2">
                        <span className="bg-gaming-neon text-black px-2 py-0.5 rounded text-sm font-bold">{categoryProducts.length}</span> 
                        Məhsul mövcuddur
                     </p>
                </div>
            </div>

            {/* Sub-Category Tabs (If any) */}
            {subCategories.length > 0 && (
                <div className="flex gap-2 overflow-x-auto pb-4 mb-4 scrollbar-hide">
                    <button 
                        onClick={() => setSelectedSubCat('ALL')}
                        className={`px-6 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition-all border ${
                            selectedSubCat === 'ALL' 
                            ? 'bg-gaming-neon text-black border-gaming-neon' 
                            : 'bg-slate-900 text-gray-400 border-gray-700 hover:text-white'
                        }`}
                    >
                        Hamısı
                    </button>
                    {subCategories.map(sub => (
                        <button 
                            key={sub}
                            onClick={() => setSelectedSubCat(sub)}
                            className={`px-6 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition-all border flex items-center gap-2 ${
                                selectedSubCat === sub 
                                ? 'bg-gaming-neon text-black border-gaming-neon' 
                                : 'bg-slate-900 text-gray-400 border-gray-700 hover:text-white'
                            }`}
                        >
                            <Tag className="w-3 h-3" /> {sub}
                        </button>
                    ))}
                </div>
            )}

            {/* Toolbar: Search & Sort */}
            <div className="bg-gaming-card border border-gray-800 rounded-2xl p-4 mb-8 sticky top-24 z-30 shadow-xl backdrop-blur-md bg-opacity-90">
                <div className="flex flex-col md:flex-row gap-4 justify-between">
                    {/* Search */}
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-3.5 text-gray-500 w-5 h-5" />
                        <input 
                            type="text" 
                            placeholder={`${category.name} daxilində axtar...`}
                            className="w-full bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-4 py-3 text-white focus:border-gaming-neon focus:ring-1 focus:ring-gaming-neon outline-none transition-all placeholder-gray-500"
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                    </div>

                    {/* Sort Dropdown */}
                    <div className="relative min-w-[200px]">
                        <div className="absolute left-3 top-3.5 pointer-events-none">
                            <ArrowDownUp className="w-5 h-5 text-gray-500" />
                        </div>
                        <select 
                            className="w-full appearance-none bg-slate-900 border border-gray-700 rounded-xl pl-10 pr-8 py-3 text-white focus:border-gaming-neon outline-none cursor-pointer"
                            value={sortOption}
                            onChange={(e) => setSortOption(e.target.value as any)}
                        >
                            <option value="default">Sıralama: Varsayılan</option>
                            <option value="price-asc">Qiymət: Ucuzdan Bahaya</option>
                            <option value="price-desc">Qiymət: Bahadan Ucuza</option>
                            <option value="name-asc">Ad: A-Z</option>
                        </select>
                        <div className="absolute right-3 top-4 pointer-events-none">
                            <Filter className="w-4 h-4 text-gray-500" />
                        </div>
                    </div>
                </div>
            </div>

            {/* Product Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProducts.map(product => (
                    <ProductCard key={product.id} product={product} />
                ))}
            </div>

            {/* Empty State */}
            {filteredProducts.length === 0 && (
                <div className="text-center py-20 bg-slate-900/30 rounded-3xl border border-dashed border-gray-800">
                    <div className="bg-slate-800 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Search className="w-8 h-8 text-gray-500"/>
                    </div>
                    <h3 className="text-xl font-bold text-white mb-2">Nəticə Tapılmadı</h3>
                    <p className="text-gray-500">Axtarışınıza uyğun məhsul yoxdur.</p>
                    <button onClick={() => { setSearch(''); setSelectedSubCat('ALL'); }} className="mt-4 text-gaming-neon font-bold hover:underline">Filtrləri Təmizlə</button>
                </div>
            )}
        </div>
    </div>
  );
};

export default CategoryPage;

