                                        <span className="absolute top-0 left-0 bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-br-lg">
                                            -{product.discountPercent}%
                                        </span>
                                    )}
                                </div>

                                <div className="flex-1 flex flex-col justify-between">
